```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_graph_statistics() {
        let graph = DependencyGraph::from_issues(&[
            issue_with_deps("a", &["b"]),
            issue_with_deps("b", &["c"]),
            issue_with_deps("c", &[]),
        ]);
        let stats = graph.statistics();
        assert_eq!(stats.nodes, 3);
        assert_eq!(stats.edges, 2);
        assert_eq!(stats.max_depth, 2);
    }

    #[test]
    fn test_graph_terminal_rendering() {
        let graph = DependencyGraph::from_issues(&[
            issue_with_deps("a", &["b"]),
            issue_with_deps("b", &[]),
        ]);
        let ctx = OutputContext::rich();
        let output = format_graph_terminal(&graph, &ctx);
        assert!(output.contains("a") && output.contains("b"));
        assert!(output.contains("►") || output.contains("->"));
    }

    #[test]
    fn test_graph_dot_output() {
        let graph = DependencyGraph::from_issues(&[
            issue_with_deps("a", &["b"]),
        ]);
        let dot = graph.to_dot();
        assert!(dot.contains("digraph"));
        assert!(dot.contains("a"));
        assert!(dot.contains("b"));
    }

    #[test]
    fn test_graph_mermaid_output() {
        let graph = DependencyGraph::from_issues(&[
            issue_with_deps("a", &["b"]),
        ]);
        let mermaid = graph.to_mermaid();
        assert!(mermaid.contains("graph") || mermaid.contains("flowchart"));
        assert!(mermaid.contains("a"));
    }

    #[test]
    fn test_node_styling_by_status() {
        let open_node = GraphNode::from_issue(&make_issue(Status::Open));
        let closed_node = GraphNode::from_issue(&make_issue(Status::Closed));

        let ctx = OutputContext::rich();
        let open_style = node_style(&open_node, &ctx);
        let closed_style = node_style(&closed_node, &ctx);

        // Closed should be dimmed
        assert_ne!(open_style, closed_style);
    }

    #[test]
    fn test_json_mode_graph() {
        let graph = DependencyGraph::from_issues(&[
            issue_with_deps("a", &["b"]),
        ]);
        let ctx = OutputContext::json();
        let output = format_graph(&graph, &ctx);
        let parsed: serde_json::Value = serde_json::from_str(&output).unwrap();
        assert!(parsed["nodes"].is_array());
        assert!(parsed["edges"].is_array());
        assert!(parsed["statistics"].is_object());
    }

    #[test]
    fn test_empty_graph() {
        let graph = DependencyGraph::from_issues(&[]);
        let ctx = OutputContext::rich();
        let output = format_graph_terminal(&graph, &ctx);
        assert!(output.contains("empty") || output.contains("No"));
    }
}
